import { API, callApi } from './authApi';

export const stationApi = {
  getAll: () =>
    callApi(API.TRUNGBO.getAll()),

  getById: (id) =>
    callApi(API.TRUNGBO.getById(id)),

  create: (data) =>
    callApi(API.TRUNGBO.create(), data),

  update: (id, data) =>
    callApi(API.TRUNGBO.update(id), data),

  delete: (id) =>
    callApi(API.TRUNGBO.delete(id)),
};
